INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100101, "獣人族", "人助け、応援", 27, 8, "人助けが大好き！　前向き格闘娘", "A", "東山奈央", 44, 155, "ヒヨリ", "トゥインクルウィッシュ", 16, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100201, "ヒューマン", "料理、人間観察", 5, 4, "戦闘のサポートが得意な、心優しい少女", "O", "種田梨沙", 47, 158, "ユイ", "トゥインクルウィッシュ", 17, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100301, "魔族", "読書、乗馬、お茶", 12, 1, "クールで何事にも真っ直ぐな剣士", "B", "早見沙織", 46, 163, "レイ", "トゥインクルウィッシュ", 18, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100401, "ヒューマン", "いたずら、探検", 10, 8, "探検好きのイタズラっ子", "O", "諸星すみれ", 27, 128, "ミソギ", "リトルリリカル", 9, 0, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100501, "獣人族", "ヒーローごっこ", 25, 11, "ヒーローに憧れる騎士見習いの少女", "O", "下田麻美", 40, 146, "マツリ", "王宮騎士団（NIGHTMARE）", 12, 0, "？？？", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100601, "魔族", "サックス", 22, 11, "甘え上手なみんなの人気者", "O", "浅倉杏美", 42, 150, "アカリ", "悪魔偽王国軍（ディアボロス）", 13, 0, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100701, "魔族", "プリンを食べること", 23, 1, "プリン大好きゴースト娘", "B", "雨宮天", 32, 130, "ミヤコ", "悪魔偽王国軍（ディアボロス）", 14, 0, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100801, "エルフ", "鏡で自分を見ること", 10, 10, "ボクは誰よりも美しい", "AB", "大空直美", 40, 150, "ユキ", "ヴァイスフリューゲル　ランドソル支部", 14, 0, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (100901, "魔族", "小説執筆", 5, 7, "前世を信じる中二病患者、「疾風の冥姫」", "A", "髙野麻美", 45, 159, "アンナ", "トワイライトキャラバン", 17, 0, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101001, "獣人族", "空想、ぬいぐるみ集め", 22, 9, "マホマホ王国のプリンセス", "O", "内田真礼", 42, 155, "マホ", "自警団（カォン）", 16, 0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101101, "ヒューマン", "お裁縫", 25, 8, "人懐っこくてマシンガントークな妹系少女", "A", "阿澄佳奈", 44, 156, "リノ", "ラビリンス", 15, 0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101201, "エルフ", "妹と遊ぶこと、二度寝、昼寝、早寝", 24, 12, "みんなのために超能力を使う眠り姫", "A", "大橋彩香", 46, 156, "ハツネ", "フォレスティエ", 17, 0, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101301, "魔族", "読書、魔法", 21, 8, "オタク全開な魔法少女", "O", "佳村はるか", 55, 166, "ナナカ", "トワイライトキャラバン", 18, 0, "", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101401, "獣人族", "読書、推理", 3, 11, "頭脳明晰な美少女名探偵", "AB", "水瀬いのり", 41, 152, "カスミ", "自警団（カォン）", 15, 0, "test", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101501, "エルフ", "絵本作り", 5, 9, "母性溢れる優しいみんなの「ミサト先生」", "O", "國府田マリ子", 54, 165, "ミサト", "フォレスティエ", 21, 0, "test", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101601, "魔族", "ファッション", 10, 4, "天真爛漫で人気者のカリスマモデル", "O", "上坂すみれ", 48, 167, "スズナ", "ルーセント学院", 17, 0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101701, "獣人族", "踊り、空手", 7, 7, "いつでも「なんくるないさ～」な天然娘", "A", "高森奈津美", 53, 158, "カオリ", "自警団（カォン）", 17, 0, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (101801, "魔族", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, 8, "多くの男性を魅了する無垢な女教師", "B", "伊藤静", 52, 162, "イオ", "ルーセント学院", 23, 0, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102001, "獣人族", "かわいいもの集め", 3, 4, "お歌もにんじんも、ウサギさんも大好き♪", "O", "日高里菜", 21, 117, "ミミ", "リトルリリカル", 10, 0, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102101, "ヒューマン", "観劇、おままごと", 9, 6, "泣き虫で臆病な守ってあげたい女の子", "B", "植田佳奈", 40, 150, "クルミ", "サレンディア救護院", 12, 0, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102201, "魔族", "ゲーム全般", 22, 11, "人見知りであまのじゃくな女の子", "O", "原紗友里", 40, 150, "ヨリ", "悪魔偽王国軍（ディアボロス）", 13, 0, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102301, "ヒューマン", "屋内でできる遊び", 10, 5, "ぷうきちといつも一緒！", "B", "芹澤優", 38, 148, "アヤネ", "サレンディア救護院", 14, 0, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102501, "ヒューマン", "ご奉仕", 12, 12, "お嬢さまのためにがんばるドジっ娘メイド", "O", "悠木碧", 43, 154, "スズメ", "サレンディア救護院", 15, 0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102601, "獣人族", "あんパン", 1, 1, "遊びと睡眠が何より大事なぐうたら娘", "B", "小岩井ことり", 42, 144, "リン", "牧場（エリザベスパーク）", 17, 0, "test", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102701, "魔族", "実験、裁縫、料理", 30, 7, "運命の相手に一途すぎる乙女", "B", "橋本ちなみ", 43, 154, "エリコ", "トワイライトキャラバン", 16, 0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102801, "エルフ", "経営、お茶会", 4, 10, "救護院を経営する優しい庶民派お嬢様", "A", "堀江由衣", 43, 156, "サレン", "サレンディア救護院", 17, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (102901, "ヒューマン", "舞台鑑賞、ダンス", 24, 1, "歌って踊れる大人気アイドル", "B", "日笠陽子", 40, 157, "ノゾミ", "カルミナ", 17, 0, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103001, "ヒューマン", "忍法開発", 31, 8, "トーゴクの神秘、オシエテクダサイ！", "O", "佐藤聡美", 51, 163, "ニノン", "ヴァイスフリューゲル　ランドソル支部", 16, 0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103101, "魔族", "占い", 22, 12, "占いが得意な霊能少女", "AB", "大坪由佳", 42, 157, "シノブ", "悪魔偽王国軍（ディアボロス）", 18, 0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103201, "ヒューマン", "慈善事業", 12, 3, "一人前の商人を目指すパワフルお嬢様", "AB", "松嵜麗", 45, 157, "アキノ", "メルクリウス財団", 18, 0, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103301, "ヒューマン", "漫才", 3, 3, "みんなを笑顔にするお笑い牧場主", "B", "新田恵海", 35, 142, "マヒル", "牧場（エリザベスパーク）", 20, 0, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103401, "エルフ", "ウインドーショッピング", 16, 3, "純情でほっとけない大人の女性", "A", "今井麻美", 55, 164, "ユカリ", "メルクリウス財団", 22, 0, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103601, "エルフ", "お勉強", 2, 2, "礼儀正しくしっかり者のちびっ子優等生", "A", "小倉唯", 21, 118, "キョウカ", "リトルリリカル", 8, 0, "test", 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103701, "ヒューマン", "剣術、年長者をからかう", 11, 8, "義理堅くてからかい好きな剣術少女", "A", "茅原実里", 43, 149, "トモ", "王宮騎士団（NIGHTMARE）", 13, 0, "test", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (103801, "獣人族", "読書、お散歩", 3, 11, "読書が趣味の病弱少女", "A", "小清水亜美", 40, 153, "シオリ", "牧場（エリザベスパーク）", 14, 0, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104001, "エルフ", "友達作りのイメトレ", 6, 6, "「友達」に憧れる、エルフの森の女の子", "AB", "花澤香菜", 44, 158, "アオイ", "フォレスティエ", 13, 0, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104201, "ヒューマン", "各種楽器", 3, 6, "人々を守るために歌う、唱喚士の少女", "O", "福原綾香", 46, 163, "チカ", "カルミナ", 17, 0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104301, "獣人族", "お菓子作り", 9, 8, "男勝りで情に厚いワイルド娘", "O", "小松未可子", 54, 168, "マコト", "自警団（カォン）", 17, 0, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104401, "魔族", "世界征服", 5, 5, "かつては夜を支配した最強の吸血鬼", "A", "丹下桜", 50, 172, "イリヤ", "悪魔偽王国軍（ディアボロス）", "??", 0, "test", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104501, "ヒューマン", "小説を読むこと", 19, 11, "妄想大好き！　ほんとは照れ屋な女の子", "AB", "長妻樹里", 49, 157, "クウカ", "ヴァイスフリューゲル　ランドソル支部", 18, 0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104601, "獣人族", "猫とたわむれること", 1, 3, "弱きを助け強きをくじく猫娘", "AB", "沼倉愛美", 48, 158, "タマキ", "メルクリウス財団", 19, 0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104701, "ヒューマン", "格闘技、湯浴み", 25, 10, "素顔を見せない冷静沈着な女性騎士", "A", "川澄綾子", 50, 171, "ジュン", "王宮騎士団（NIGHTMARE）", 25, 0, "？？？", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104801, "ヒューマン", "傭兵などのアルバイト", 11, 11, "仕事も私事も効率優先な傭兵少女", "O", "田所あずさ", 49, 163, "ミフユ", "メルクリウス財団", 20, 0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (104901, "ヒューマン", "家事全般", 24, 10, "お姉ちゃんがお世話してあげるからねっ！", "O", "生天目仁美", 54, 168, "シズル", "ラビリンス", 18, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105001, "魔族", "ファッション誌鑑賞、コスメ集め", 3, 1, "ちょっとおませな恋に恋する女の子", "A", "久野美咲", 22, 120, "ミサキ", "ルーセント学院", 11, 0, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105101, "ヒューマン", "研究、実験", 7, 3, "実験が趣味の危険な科学者", "A", "三石琴乃", 53, 166, "ミツキ", "トワイライトキャラバン", 27, 0, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105201, "獣人族", "毛繕い、お喋り", 14, 3, "乙女チックなもふもふアニマル", "A", "徳井青空", 100, 150, "リマ", "牧場（エリザベスパーク）", 17, 0, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105301, "ヒューマン", "お菓子屋通い", 28, 7, "見た目も中身もお子ちゃまな異国の軍人", "A", "辻あゆみ", 33, 140, "モニカ", "ヴァイスフリューゲル　ランドソル支部", 17, 0, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105401, "ヒューマン", "裁縫", 7, 9, "ファッション大好きなキュートガール", "AB", "木戸衣吹", 45, 153, "ツムギ", "カルミナ", 14, 0, "test", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105501, "エルフ", "観察", 7, 4, "どこまでも一途に慕う、純情乙女", "O", "大関英里", 43, 155, "アユミ", "ヴァイスフリューゲル　ランドソル支部", 16, 0, "test", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105601, "ヒューマン", "釣り", 11, 7, "人情味溢れる粋でいなせな「姉御」", "B", "佐藤利奈", 54, 167, "ルカ", "トワイライトキャラバン", 25, 0, "test", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105701, "ヒューマン", "冒険、おしゃべり", 10, 3, "空への冒険を夢見る騎空士の少女", "O", "金元寿子", 45, 156, "ジータ", "？？？", 17, 0, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105801, "ヒューマン", "食べ歩き、料理", 31, 3, "いつも元気な腹ペコ少女", "O", "M・A・O", 46, 156, "ペコリーヌ", "美食殿", 17, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (105901, "エルフ", "瞑想、動植物の飼育", 11, 5, "主を慕う、小さなガイド役", "B", "伊藤美来", 35, 140, "コッコロ", "美食殿", 11, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106001, "獣人族", "猫と遊ぶ", 2, 9, "行き倒れの謎のネコミミ魔法使い", "A", "立花理香", 39, 152, "キャル", "美食殿", 14, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106101, "ヒューマン", "冒険、思い出話", 11, 8, "さまよえる謎の少女", "O", "潘めぐみ", 40, 148, "ムイミ", "？？？", 16, 0, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106301, "エルフ", "キレイな葉っぱを集めること", 17, 6, "森番を目指すエルフの少女", "O", "優木かな", 42, 155, "アリサ", "？？？", 15, 0, "", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106401, "ドラゴン族", "読書、ストレッチ", 14, 12, "記憶喪失のドラゴン娘", "B", "近藤玲奈", "???", 147, "シェフィ", "美食殿", 14, 0, "", 1);
