INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106601, "ドラゴン族", "ゲーム", 29, 9, "口が達者なヘタレドラゴン", "AB", "藤田茜", "???", 145, "イノリ", "ドラゴンズネスト", 13, 0, "", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106701, "ドラゴン族", "絵画、読書", 17, 4, "妖しい微笑で全てを見透かす臥竜の頭領", "O", "大西沙織", "???", 168, "ホマレ", "ドラゴンズネスト", 25, 0, "", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106801, "ヒューマン", "人間観察", 25, 7, "秘密結社ラビリンスの『迷宮女王』", "AB", "沢城みゆき", "??", 160, "ラビリスタ", "ラビリンス", 25, 0, "", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (106901, "獣人族", "占い、支配", 1, 7, "謎に包まれたランドソルの主", "AB", "蒼井翔太", "??", 166, "カイザーインサイト", "？？？", 29, 0, "", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107001, "エルフ", "物真似、芸術鑑賞", 24, 3, "研究所に隠れ住む物静かなお姉さん", "O", "井口裕香", "??", 149, "ネネカ", "？？？", 24, 0, "", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107101, "ヒューマン", "強敵との闘争", 7, 2, "傍若無人な王宮騎士団副団長", "O", "たかはし智秋", "??", 165, "クリスティーナ", "王宮騎士団（NIGHTMARE）", 27, 0, "", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107501, "ヒューマン", "食べ歩き、料理", 31, 3, "いつも元気な腹ペコ少女", "O", "M・A・O", 46, 156, "ペコリーヌ（サマー）", "美食殿", 17, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107601, "エルフ", "瞑想、動植物の飼育", 11, 5, "主を慕う、小さなガイド役", "B", "伊藤美来", 35, 140, "コッコロ（サマー）", "美食殿", 11, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107701, "ヒューマン", "ご奉仕", 12, 12, "お嬢さまのためにがんばるドジっ娘メイド", "O", "悠木碧", 43, 154, "スズメ（サマー）", "サレンディア救護院", 15, 0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107801, "獣人族", "猫と遊ぶ", 2, 9, "行き倒れの謎のネコミミ魔法使い", "A", "立花理香", 39, 152, "キャル（サマー）", "美食殿", 14, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (107901, "獣人族", "猫とたわむれること", 1, 3, "弱きを助け強きをくじく猫娘", "AB", "沼倉愛美", 48, 158, "タマキ（サマー）", "メルクリウス財団", 19, 0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108001, "ヒューマン", "傭兵などのアルバイト", 11, 11, "仕事も私事も効率優先な傭兵少女", "O", "田所あずさ", 49, 163, "ミフユ（サマー）", "メルクリウス財団", 20, 0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108101, "魔族", "占い", 22, 12, "占いが得意な霊能少女", "AB", "大坪由佳", 42, 157, "シノブ（ハロウィン）", "悪魔偽王国軍（ディアボロス）", 18, 0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108201, "魔族", "プリンを食べること", 23, 1, "プリン大好きゴースト娘", "B", "雨宮天", 32, 130, "ミヤコ（ハロウィン）", "悪魔偽王国軍（ディアボロス）", 14, 0, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108301, "魔族", "ファッション誌鑑賞、コスメ集め", 3, 1, "ちょっとおませな恋に恋する女の子", "A", "久野美咲", 22, 120, "ミサキ（ハロウィン）", "ルーセント学院", 11, 0, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108401, "ヒューマン", "各種楽器", 3, 6, "人々を守るために歌う、唱喚士の少女", "O", "福原綾香", 46, 163, "チカ（クリスマス）", "カルミナ", 17, 0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108501, "ヒューマン", "観劇、おままごと", 9, 6, "泣き虫で臆病な守ってあげたい女の子", "B", "植田佳奈", 40, 150, "クルミ（クリスマス）", "サレンディア救護院", 12, 0, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108601, "ヒューマン", "屋内でできる遊び", 10, 5, "ぷうきちといつも一緒！", "B", "芹澤優", 38, 148, "アヤネ（クリスマス）", "サレンディア救護院", 14, 0, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108701, "獣人族", "人助け、応援", 27, 8, "人助けが大好き！　前向き格闘娘", "A", "東山奈央", 44, 155, "ヒヨリ（ニューイヤー）", "トゥインクルウィッシュ", 16, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108801, "ヒューマン", "料理、人間観察", 5, 4, "戦闘のサポートが得意な、心優しい少女", "O", "種田梨沙", 47, 158, "ユイ（ニューイヤー）", "トゥインクルウィッシュ", 17, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (108901, "魔族", "読書、乗馬、お茶", 12, 1, "クールで何事にも真っ直ぐな剣士", "B", "早見沙織", 46, 163, "レイ（ニューイヤー）", "トゥインクルウィッシュ", 18, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109001, "魔族", "実験、裁縫、料理", 30, 7, "運命の相手に一途すぎる乙女", "B", "橋本ちなみ", 43, 154, "エリコ（バレンタイン）", "トワイライトキャラバン", 16, 0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109101, "ヒューマン", "家事全般", 24, 10, "お姉ちゃんがお世話してあげるからねっ！", "O", "生天目仁美", 54, 168, "シズル（バレンタイン）", "ラビリンス", 18, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109201, "ヒューマン", "読書", 1, 12, "英霊と契約を結んだマナリアの天才王女", "AB", "日笠陽子", 55, 156, "アン", "？？？", 17, 0, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109301, "ヒューマン", "食べること、眠ること", 4, 2, "マナリア魔法学院の新入生", "O", "こやまきみこ", 45, 144, "ルゥ", "？？？", 16, 0, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109401, "半人半竜", "ピアノ", 3, 11, "人を超越した力を有す心優しい竜姫", "B", "福原綾香", 67, 167, "グレア", "？？？", 17, 0, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109501, "ヒューマン", "小説を読むこと", 19, 11, "妄想大好き！　ほんとは照れ屋な女の子", "AB", "長妻樹里", 49, 157, "クウカ（オーエド）", "ヴァイスフリューゲル　ランドソル支部", 18, 0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109601, "ヒューマン", "忍法開発", 31, 8, "トーゴクの神秘、オシエテクダサイ！", "O", "佐藤聡美", 51, 163, "ニノン（オーエド）", "ヴァイスフリューゲル　ランドソル支部", 16, 0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109701, "鬼族", "演劇鑑賞、詩文", 2, 2, "鬼がかりの万能妹メイド", "?", "水瀬いのり", "??", 154, "レム", "？？？", 17, 0, "", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109801, "鬼族", "読書", 2, 2, "毒舌系鬼姉メイド", "?", "村川梨衣", "??", 154, "ラム", "？？？", 17, 0, "", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (109901, "ハーフエルフ", "パックの毛繕い、勉強", 23, 9, "銀髪のおっとりハーフエルフ", "?", "高橋李依", "??", 164, "エミリア", "？？？", "??", 0, "", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (110001, "魔族", "ファッション", 10, 4, "天真爛漫で人気者のカリスマモデル", "O", "上坂すみれ", 48, 167, "スズナ（サマー）", "ルーセント学院", 17, 0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (110101, "魔族", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, 8, "多くの男性を魅了する無垢な女教師", "B", "伊藤静", 52, 162, "イオ（サマー）", "ルーセント学院", 23, 0, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (110201, "魔族", "ファッション誌鑑賞、コスメ集め", 3, 1, "ちょっとおませな恋に恋する女の子", "A", "久野美咲", 22, 120, "ミサキ（サマー）", "ルーセント学院", 11, 0, "", 14);
