INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (110401, "獣人族", "お菓子作り", 9, 8, "男勝りで情に厚いワイルド娘", "O", "小松未可子", 54, 168, "マコト（サマー）", "自警団（カォン）", 17, 0, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (110501, "獣人族", "踊り、空手", 7, 7, "いつでも「なんくるないさ～」な天然娘", "A", "高森奈津美", 53, 158, "カオリ（サマー）", "自警団（カォン）", 17, 0, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (110601, "獣人族", "空想、ぬいぐるみ集め", 22, 9, "マホマホ王国のプリンセス", "O", "内田真礼", 42, 155, "マホ（サマー）", "自警団（カォン）", 16, 0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 10);
