INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (111801, "ヒューマン", "食べ歩き、料理", 31, 3, "いつも元気な腹ペコ少女", "O", "M・A・O", 46, 156, "ぺコリーヌ（ニューイヤー）", "美食殿", 17, 0, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (111901, "エルフ", "瞑想、動植物の飼育", 11, 5, "主を慕う、小さなガイド役", "B", "伊藤美来", 35, 140, "コッコロ（ニューイヤー）", "美食殿", 11, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (112001, "獣人族", "猫と遊ぶ", 2, 9, "行き倒れの謎のネコミミ魔法使い", "A", "立花理香", 39, 152, "キャル（ニューイヤー）", "美食殿", 14, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (112101, "ヒューマン", "ご奉仕", 12, 12, "お嬢さまのためにがんばるドジっ娘メイド", "O", "悠木碧", 43, 154, "スズメ（ニューイヤー）", "サレンディア救護院", 15, 0, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (112201, "獣人族", "読書、推理", 3, 11, "頭脳明晰な美少女名探偵", "AB", "水瀬いのり", 41, 152, "カスミ（マジカル）", "自警団（カォン）", 15, 0, "", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (112301, "獣人族", "読書、お散歩", 3, 11, "読書が趣味の病弱少女", "A", "小清水亜美", 40, 153, "シオリ（マジカル）", "牧場（エリザベスパーク）", 14, 0, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (112401, "ヒューマン", "友達と長話", 24, 4, "弾ける笑顔！　アイドルを夢見る女の子", "O", "大橋彩香", 45, 159, "ウヅキ（デレマス）", "ニュージェネレーションズ", 17, 0, "", 100);
