INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (112701, "獣人族", "あんパン", 1, 1, "遊びと睡眠が何より大事なぐうたら娘", "B", "小岩井ことり", 42, 144, "リン（レンジャー）", "牧場（エリザベスパーク）", 17, 0, "", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (112801, "ヒューマン", "漫才", 3, 3, "みんなを笑顔にするお笑い牧場主", "B", "新田恵海", 35, 142, "マヒル（レンジャー）", "牧場（エリザベスパーク）", 20, 0, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (112901, "ヒューマン", "お裁縫", 25, 8, "人懐っこくてマシンガントークな妹系少女", "A", "阿澄佳奈", 44, 156, "リノ（ワンダー）", "ラビリンス", 15, 0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113001, "エルフ", "観察", 7, 4, "どこまでも一途に慕う、純情乙女", "O", "大関英里", 43, 155, "アユミ（ワンダー）", "ヴァイスフリューゲル　ランドソル支部", 16, 0, "", 15);
