INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113201, "魔族", "小説執筆", 5, 7, "前世を信じる中二病患者、「疾風の冥姫」", "A", "髙野麻美", 45, 159, "アンナ（サマー）", "トワイライトキャラバン", 17, 0, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113301, "魔族", "読書、魔法", 21, 8, "オタク全開な魔法少女", "O", "佳村はるか", 55, 166, "ナナカ（サマー）", "トワイライトキャラバン", 18, 0, "", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113401, "エルフ", "妹と遊ぶこと、二度寝、昼寝、早寝", 24, 12, "みんなのために超能力を使う眠り姫", "A", "大橋彩香", 46, 156, "ハツネ（サマー）", "フォレスティエ", 17, 0, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113501, "エルフ", "絵本作り", 5, 9, "母性溢れる優しいみんなの「ミサト先生」", "O", "國府田マリ子", 54, 165, "ミサト（サマー）", "フォレスティエ", 21, 0, "", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113601, "ヒューマン", "格闘技、湯浴み", 25, 10, "素顔を見せない冷静沈着な女性騎士", "A", "川澄綾子", 50, 171, "ジュン（サマー）", "王宮騎士団（NIGHTMARE）", 25, 0, "", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113701, "魔族", "サックス", 22, 11, "甘え上手なみんなの人気者", "O", "浅倉杏美", 42, 150, "アカリ（エンジェル）", "悪魔偽王国軍（ディアボロス）", 13, 0, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113801, "魔族", "ゲーム全般", 22, 11, "人見知りであまのじゃくな女の子", "O", "原紗友里", 40, 150, "ヨリ（エンジェル）", "悪魔偽王国軍（ディアボロス）", 13, 0, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (113901, "ヒューマン", "裁縫", 7, 9, "ファッション大好きなキュートガール", "AB", "木戸衣吹", 45, 153, "ツムギ（ハロウィン）", "カルミナ", 14, 0, "", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (114001, "魔族", "読書、乗馬、お茶", 12, 1, "クールで何事にも真っ直ぐな剣士", "B", "早見沙織", 46, 163, "レイ（ハロウィン）", "トゥインクルウィッシュ", 18, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (114101, "獣人族", "ヒーローごっこ", 25, 11, "ヒーローに憧れる騎士見習いの少女", "O", "下田麻美", 40, 146, "マツリ（ハロウィン）", "王宮騎士団（NIGHTMARE）", 12, 0, "", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (114201, "ヒューマン", "お菓子屋通い", 28, 7, "見た目も中身もお子ちゃまな異国の軍人", "A", "辻あゆみ", 33, 140, "モニカ（マジカル）", "ヴァイスフリューゲル　ランドソル支部", 17, 0, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (114301, "ヒューマン", "剣術、年長者をからかう", 11, 8, "義理堅くてからかい好きな剣術少女", "A", "茅原実里", 43, 149, "トモ（マジカル）", "王宮騎士団（NIGHTMARE）", 13, 0, "", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (114401, "ヒューマン", "慈善事業", 12, 3, "一人前の商人を目指すパワフルお嬢様", "AB", "松嵜麗", 45, 157, "アキノ（クリスマス）", "メルクリウス財団", 18, 0, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (114501, "エルフ", "経営、お茶会", 4, 10, "救護院を経営する優しい庶民派お嬢様", "A", "堀江由衣", 43, 156, "サレン（クリスマス）", "サレンディア救護院", 17, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (114601, "エルフ", "ウインドーショッピング", 16, 3, "純情でほっとけない大人の女性", "A", "今井麻美", 55, 164, "ユカリ（クリスマス）", "メルクリウス財団", 22, 0, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (114701, "ヒューマン", "冒険、思い出話", 11, 8, "さまよえる謎の少女", "O", "潘めぐみ", 40, 148, "ムイミ（ニューイヤー）", "？？？", 16, 0, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115001, "エルフ", "物真似、芸術鑑賞", 24, 3, "研究所に隠れ住む物静かなお姉さん", "O", "井口裕香", "??", 149, "ネネカ（ニューイヤー）", "？？？", 24, 0, "", "");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115501, "エルフ", "瞑想、動植物の飼育", 11, 5, "主を慕う、小さなガイド役", "B", "伊藤美来", 35, 140, "コッコロ（儀装束）", "美食殿", 11, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115601, "ヒューマン", "料理、人間観察", 5, 4, "戦闘のサポートが得意な、心優しい少女", "O", "種田梨沙", 47, 158, "ユイ（儀装束）", "トゥインクルウィッシュ", 17, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115701, "獣人族", "読書、推理", 3, 11, "頭脳明晰な美少女名探偵", "AB", "水瀬いのり", 41, 152, "カスミ（サマー）", "自警団（カォン）", 15, 0, "", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115801, "獣人族", "毛繕い、お喋り", 14, 3, "乙女チックなもふもふアニマル", "A", "徳井青空", 100, 150, "リマ（シンデレラ）", "牧場（エリザベスパーク）", 17, 0, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (115901, "獣人族", "お菓子作り", 9, 8, "男勝りで情に厚いワイルド娘", "O", "小松未可子", 54, 168, "マコト（シンデレラ）", "自警団（カォン）", 17, 0, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116001, "獣人族", "空想、ぬいぐるみ集め", 22, 9, "マホマホ王国のプリンセス", "O", "内田真礼", 42, 155, "マホ（シンデレラ）", "自警団（カォン）", 16, 0, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116201, "エルフ", "ダーツ", 7, 8, "ダウンタウン育ちのダウナー系エルフ", "O", "種﨑敦美", 42, 154, "クロエ（聖学祭）", "聖テレサ女学院（なかよし部）", 17, 0, "", 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116301, "ヒューマン", "ダンス、カラオケ", 15, 9, "自由奔放ナチュラル無礼な現代っ子", "O", "佐倉綾音", 46, 156, "チエル（聖学祭）", "聖テレサ女学院（なかよし部）", 16, 0, "", 16);
