INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116501, "ドラゴン族", "ゲーム", 29, 9, "口が達者なヘタレドラゴン", "AB", "藤田茜", "???", 145, "イノリ（タイムトラベル）", "ドラゴンズネスト", 13, 0, "", 17);
