INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116701, "エルフ", "友達作りのイメトレ", 6, 6, "「友達」に憧れる、エルフの森の女の子", "AB", "花澤香菜", 44, 158, "アオイ（作業服）", "フォレスティエ", 13, 0, "", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116801, "獣人族", "猫とたわむれること", 1, 3, "弱きを助け強きをくじく猫娘", "AB", "沼倉愛美", 48, 158, "タマキ（作業服）", "メルクリウス財団", 19, 0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (116901, "ヒューマン", "傭兵などのアルバイト", 11, 11, "仕事も私事も効率優先な傭兵少女", "O", "田所あずさ", 49, 163, "ミフユ（作業服）", "メルクリウス財団", 20, 0, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117001, "魔族", "実験、裁縫、料理", 30, 7, "運命の相手に一途すぎる乙女", "B", "橋本ちなみ", 43, 154, "エリコ（サマー）", "トワイライトキャラバン", 16, 0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117101, "ヒューマン", "家事全般", 24, 10, "お姉ちゃんがお世話してあげるからねっ！", "O", "生天目仁美", 54, 168, "シズル（サマー）", "ラビリンス", 18, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117201, "ヒューマン", "舞台鑑賞、ダンス", 24, 1, "歌って踊れる大人気アイドル", "B", "日笠陽子", 40, 157, "ノゾミ（サマー）", "カルミナ", 17, 0, "", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117301, "ヒューマン", "各種楽器", 3, 6, "人々を守るために歌う、唱喚士の少女", "O", "福原綾香", 46, 163, "チカ（サマー）", "カルミナ", 17, 0, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117401, "ヒューマン", "裁縫", 7, 9, "ファッション大好きなキュートガール", "AB", "木戸衣吹", 45, 153, "ツムギ（サマー）", "カルミナ", 14, 0, "", 4);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117501, "ヒューマン", "研究、実験", 7, 3, "実験が趣味の危険な科学者", "A", "三石琴乃", 53, 166, "ミツキ（オーエド）", "トワイライトキャラバン", 27, 0, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117601, "エルフ", "鏡で自分を見ること", 10, 10, "ボクは誰よりも美しい", "AB", "大空直美", 40, 150, "ユキ（オーエド）", "ヴァイスフリューゲル　ランドソル支部", 14, 0, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117701, "獣人族", "踊り、空手", 7, 7, "いつでも「なんくるないさ～」な天然娘", "A", "高森奈津美", 53, 158, "カオリ（ハロウィン）", "自警団（カォン）", 17, 0, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117801, "ヒューマン", "忍法開発", 31, 8, "トーゴクの神秘、オシエテクダサイ！", "O", "佐藤聡美", 51, 163, "ニノン（ハロウィン）", "ヴァイスフリューゲル　ランドソル支部", 16, 0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (117901, "魔族", "ファッション", 10, 4, "天真爛漫で人気者のカリスマモデル", "O", "上坂すみれ", 48, 167, "スズナ（ハロウィン）", "ルーセント学院", 17, 0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (118001, "ヒューマン", "お金を数えること、悪だくみ", 19, 9, "忠義に目覚めた女商人", "A", "Lynn", 57, 160, "クレジッタ", "リッチモンド商工会", 26, 0, "", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (118101, "魔族", "歌、読書、詩を書くこと", 28, 12, "静寂を求め歌う陰気少女", "O", "原田彩楓", 53, 165, "ランファ", "レイジ・レギオン", 20, 0, "", 19);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (118201, "ヒューマン", "特に無し", 2, 7, "明朗快活、なれど破滅に流るる溌溂少女", "A", "鬼頭明里", "??", 159, "ミソラ", "レイジ・レギオン", 16, 0, "", 19);
