INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (119001, "魔族", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, 8, "多くの男性を魅了する無垢な女教師", "B", "伊藤静", 52, 162, "イオ（ノワール）", "ルーセント学院", 23, 0, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (119101, "ヒューマン", "小説を読むこと", 19, 11, "妄想大好き！　ほんとは照れ屋な女の子", "AB", "長妻樹里", 49, 157, "クウカ（ノワール）", "ヴァイスフリューゲル　ランドソル支部", 18, 0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (119201, "ヒューマン", "漫才", 3, 3, "みんなを笑顔にするお笑い牧場主", "B", "新田恵海", 35, 142, "マヒル（クリスマス）", "牧場（エリザベスパーク）", 20, 0, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 11);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (119301, "ヒューマン", "お裁縫", 25, 8, "人懐っこくてマシンガントークな妹系少女", "A", "阿澄佳奈", 44, 156, "リノ（クリスマス）", "ラビリンス", 15, 0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (119901, "魔族", "プリンを食べること", 23, 1, "プリン大好きゴースト娘", "B", "雨宮天", 32, 130, "ミヤコ（クリスマス）", "悪魔偽王国軍（ディアボロス）", 14, 0, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (120001, "ヒューマン", "家事全般", 24, 10, "お姉ちゃんがお世話してあげるからねっ！", "O", "生天目仁美", 54, 168, "シズル（ノワール）", "ラビリンス", 18, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (120701, "ドラゴン族", "読書、ストレッチ", 14, 12, "記憶喪失のドラゴン娘", "B", "近藤玲奈", "???", 147, "シェフィ（ニューイヤー）", "美食殿", 14, 0, "", 1);
