INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (120901, "魔族", "世界征服", 5, 5, "かつては夜を支配した最強の吸血鬼", "A", "丹下桜", 50, 172, "イリヤ（ニューイヤー）", "悪魔偽王国軍（ディアボロス）", "??", 0, "", 7);
