INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (121101, "獣人族", "猫と遊ぶ", 2, 9, "行き倒れの謎のネコミミ魔法使い", "A", "立花理香", 39, 152, "キャル（オーバーロード）", "美食殿", 14, 0, "", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (121201, "ヒューマン", "人間観察", 25, 7, "秘密結社ラビリンスの『迷宮女王』", "AB", "沢城みゆき", "??", 160, "ラビリスタ（オーバーロード）", "ラビリンス", 25, 0, "", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (121301, "ヒューマン", "観劇、おままごと", 9, 6, "泣き虫で臆病な守ってあげたい女の子", "B", "植田佳奈", 40, 150, "クルミ（ステージ）", "サレンディア救護院", 12, 0, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (121401, "魔族", "ファッション誌鑑賞、コスメ集め", 3, 1, "ちょっとおませな恋に恋する女の子", "A", "久野美咲", 22, 120, "ミサキ（ステージ）", "ルーセント学院", 11, 0, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 14);
