INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (121901, "魔族", "小説執筆", 5, 7, "前世を信じる中二病患者、「疾風の冥姫」", "A", "髙野麻美", 45, 159, "アンナ（パイレーツ）", "トワイライトキャラバン", 17, 0, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122001, "魔族", "占い", 22, 12, "占いが得意な霊能少女", "AB", "大坪由佳", 42, 157, "シノブ（パイレーツ）", "悪魔偽王国軍（ディアボロス）", 18, 0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122101, "エルフ", "友達作りのイメトレ", 6, 6, "「友達」に憧れる、エルフの森の女の子", "AB", "花澤香菜", 44, 158, "アオイ（キャンプ）", "フォレスティエ", 13, 0, "", 6);
