INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122401, "獣人族", "人助け、応援", 27, 8, "人助けが大好き！　前向き格闘娘", "A", "東山奈央", 44, 155, "ヒヨリ（サマー）", "トゥインクルウィッシュ", 16, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122501, "魔族", "読書、乗馬、お茶", 12, 1, "クールで何事にも真っ直ぐな剣士", "B", "早見沙織", 46, 163, "レイ（サマー）", "トゥインクルウィッシュ", 18, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122601, "ヒューマン", "料理、人間観察", 5, 4, "戦闘のサポートが得意な、心優しい少女", "O", "種田梨沙", 47, 158, "ユイ（サマー）", "トゥインクルウィッシュ", 17, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2);
