INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122801, "ヒューマン", "いたずら、探検", 10, 8, "探検好きのイタズラっ子", "O", "諸星すみれ", 27, 128, "ミソギ（サマー）", "リトルリリカル", 9, 0, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (122901, "獣人族", "かわいいもの集め", 3, 4, "お歌もにんじんも、ウサギさんも大好き♪", "O", "日高里菜", 21, 117, "ミミ（サマー）", "リトルリリカル", 10, 0, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 5);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (123001, "？？？", "？？？", "?", "?", "新たな姿で騎士の冒険を支え続ける妖精", "?", "相坂優歌", "???", 150, "アメス", "？？？", "??", 0, "", "");
