INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (125101, "獣人族", "猫とたわむれること", 1, 3, "弱きを助け強きをくじく猫娘", "AB", "沼倉愛美", 48, 158, "タマキ（カフェ）", "メルクリウス財団", 19, 0, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (125201, "ヒューマン", "お菓子屋通い", 28, 7, "見た目も中身もお子ちゃまな異国の軍人", "A", "辻あゆみ", 33, 140, "モニカ（カフェ）", "ヴァイスフリューゲル　ランドソル支部", 17, 0, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 15);
