INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (125401, "獣人族", "読書、お散歩", 3, 11, "読書が趣味の病弱少女", "A", "小清水亜美", 40, 153, "シオリ（レンジャー）", "牧場（エリザベスパーク）", 14, 0, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11);
