INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (126901, "魔族", "歌、読書、詩を書くこと", 28, 12, "静寂を求め歌う陰気少女", "O", "原田彩楓", 53, 165, "ランファ（サマー）", "レイジ・レギオン", 20, 0, "", 19);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127001, "ヒューマン", "小説を読むこと", 19, 11, "妄想大好き！　ほんとは照れ屋な女の子", "AB", "長妻樹里", 49, 157, "クウカ（サマー）", "ヴァイスフリューゲル　ランドソル支部", 18, 0, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127101, "魔族", "占い", 22, 12, "占いが得意な霊能少女", "AB", "大坪由佳", 42, 157, "シノブ（サマー）", "悪魔偽王国軍（ディアボロス）", 18, 0, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 7);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127201, "獣人族", "猫と遊ぶ", 2, 9, "行き倒れの謎のネコミミ魔法使い", "A", "立花理香", 39, 152, "キャル（編入生）", "美食殿", 14, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127301, "魔族", "ファッション", 10, 4, "天真爛漫で人気者のカリスマモデル", "O", "上坂すみれ", 48, 167, "スズナ（編入生）", "ルーセント学院", 17, 0, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127501, "エルフ", "経営、お茶会", 4, 10, "救護院を経営する優しい庶民派お嬢様", "A", "堀江由衣", 43, 156, "サレン（サラサリア）", "サレンディア救護院", 17, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (127601, "ヒューマン", "釣り", 11, 7, "人情味溢れる粋でいなせな「姉御」", "B", "佐藤利奈", 54, 167, "ルカ（サラサリア）", "トワイライトキャラバン", 25, 0, "", 13);
