INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128301, "ドラゴン族", "ゲーム", 29, 9, "口が達者なヘタレドラゴン", "AB", "藤田茜", "???", 145, "イノリ（ニューイヤー）", "ドラゴンズネスト", 13, 0, "", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128401, "エルフ", "妹と遊ぶこと、二度寝、昼寝、早寝", 24, 12, "みんなのために超能力を使う眠り姫", "A", "大橋彩香", 46, 156, "ハツネ（ニューイヤー）", "フォレスティエ", 17, 0, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 6);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128501, "獣人族", "読書、推理", 3, 11, "頭脳明晰な美少女名探偵", "AB", "水瀬いのり", 41, 152, "カスミ（ニューイヤー）", "自警団（カォン）", 15, 0, "", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128701, "獣人族", "人助け、応援", 27, 8, "人助けが大好き！　前向き格闘娘", "A", "東山奈央", 44, 155, "ヒヨリ（アストラル）", "トゥインクルウィッシュ", 16, 0, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128801, "魔族", "読書、乗馬、お茶", 12, 1, "クールで何事にも真っ直ぐな剣士", "B", "早見沙織", 46, 163, "レイ（アストラル）", "トゥインクルウィッシュ", 18, 0, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (128901, "ヒューマン", "料理、人間観察", 5, 4, "戦闘のサポートが得意な、心優しい少女", "O", "種田梨沙", 47, 158, "ユイ（アストラル）", "トゥインクルウィッシュ", 17, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2);
