INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (129901, "魔族", "実験、裁縫、料理", 30, 7, "運命の相手に一途すぎる乙女", "B", "橋本ちなみ", 43, 154, "エリコ（コマンダー）", "トワイライトキャラバン", 16, 0, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 13);
