INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (133501, "エルフ", "経営、お茶会", 4, 10, "救護院を経営する優しい庶民派お嬢様", "A", "堀江由衣", 43, 156, "サレン（ニューイヤー）", "サレンディア救護院", 17, 0, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 9);
