INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (136301, "ヒューマン", "特に無し", 2, 7, "明朗快活、なれど破滅に流るる溌溂少女", "A", "鬼頭明里", "??", 159, "ミソラ（クリスマス）", "レイジ・レギオン", 16, 0, "", 19);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (136401, "ヒューマン", "料理、人間観察", 5, 4, "戦闘のサポートが得意な、心優しい少女", "O", "種田梨沙", 47, 158, "ユイ（クリスマス）", "トゥインクルウィッシュ", 17, 0, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 2);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (136501, "ヒューマン", "家事全般", 24, 10, "お姉ちゃんがお世話してあげるからねっ！", "O", "生天目仁美", 54, 168, "シズル（ニューイヤー）", "ラビリンス", 18, 0, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 3);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (137101, "ヒューマン", "忍法開発", 31, 8, "トーゴクの神秘、オシエテクダサイ！", "O", "佐藤聡美", 51, 163, "ニノン（サマー）", "ヴァイスフリューゲル　ランドソル支部", 16, 0, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 15);
