INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (137601, "エルフ", "瞑想、動植物の飼育", 11, 5, "主を想い、“進化”したガイド役", "B", "伊藤美来", 48, 164, "コッコロ（嚮導幼君）", "美食殿", 11, 0, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 1);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (137901, "ヒューマン", "お裁縫", 25, 8, "人懐っこくてマシンガントークな妹系少女", "A", "阿澄佳奈", 44, 156, "リノ（ニューイヤー）", "ラビリンス", 15, 0, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 3);
