INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (139101, "獣人族", "猫と遊ぶ", 2, 9, "行き倒れの謎のネコミミ魔法使い", "A", "立花理香", 39, 152, "キャル（覇瞳天星）", "美食殿", 14, 0, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 1);
